{
  "terms": [
    {
      "term": "Statutory Regulations",
      "simpleDefinition": "Legally binding acts of Parliament that must be followed; failure to comply is a criminal offense.",
      "anchor": "Statutory equals Law.",
      "misconception": "Thinking statutory regulations are just optional suggestions or 'best practice' rather than legal requirements."
    },
    {
      "term": "Non-statutory Regulations",
      "simpleDefinition": "Guidance documents and technical standards that provide instructions on how to work safely, but are not laws themselves.",
      "anchor": "Non-statutory equals Guidance.",
      "misconception": "Assuming that because they aren't law, they can be ignored without any legal or professional consequence."
    },
    {
      "term": "HASAWA (Health and Safety at Work Act)",
      "simpleDefinition": "The main statutory law that sets out the general duties of employers and employees to ensure health and safety at work.",
      "anchor": "The 'Umbrella Act' for all workplace safety.",
      "misconception": "Believing that HASAWA only places responsibility on the employer and not the individual electrician."
    },
    {
      "term": "EAWR (Electricity at Work Regulations)",
      "simpleDefinition": "Statutory regulations that specifically focus on the safe use and maintenance of electrical systems to prevent injury.",
      "anchor": "The legal rulebook for electrical safety.",
      "misconception": "Confusing the EAWR (the law) with BS 7671 (the technical standard)."
    },
    {
      "term": "BS 7671",
      "simpleDefinition": "The national non-statutory standard for electrical installations in the UK, also known as the IET Wiring Regulations.",
      "anchor": "The electrician's 'Bible' for technical work.",
      "misconception": "Believing BS 7671 is a statutory law; it is actually a non-statutory technical standard."
    },
    {
      "term": "On-Site Guide",
      "simpleDefinition": "A non-statutory handbook that provides a simplified, practical version of BS 7671 for common electrical tasks.",
      "anchor": "A pocket-sized summary of the Wiring Regs.",
      "misconception": "Thinking the On-Site Guide covers every complex installation scenario found in the full BS 7671."
    },
    {
      "term": "PPE (Personal Protective Equipment)",
      "simpleDefinition": "Statutory regulations requiring the use of protective gear like boots, gloves, and goggles to minimize workplace risks.",
      "anchor": "Your last line of defense against injury.",
      "misconception": "Thinking PPE is optional if the task is small or 'only takes a minute'."
    },
    {
      "term": "COSHH",
      "simpleDefinition": "Statutory regulations that require employers to control substances that are hazardous to health, such as chemicals or dust.",
      "anchor": "Safety rules for handling dangerous substances.",
      "misconception": "Thinking COSHH only applies to liquid chemicals and not to things like solder fumes or masonry dust."
    }
  ],
  "anchorPhrases": [
    "Statutory equals Law.",
    "Non-statutory equals Guidance.",
    "BS 7671 is the standard, not the law.",
    "EAWR is the law for electricity.",
    "HASAWA is the umbrella for all safety."
  ],
  "misconceptionTargets": [
    "Believing BS 7671 is a statutory law.",
    "Thinking non-statutory guidance is optional and can be ignored.",
    "Confusing technical guidance with legal acts.",
    "Assuming only employers have duties under statutory regulations."
  ]
}

{
  "lessonAim": "To enable the learner to distinguish between statutory regulations (law) and non-statutory guidance (best practice) within the UK electrical industry.",
  "teachChecks": [
    {
      "title": "Statutory Regulations",
      "objective": "Identify and define statutory regulations as legally binding requirements.",
      "retrievalTextLines": [
        "In the UK electrical industry, 'Statutory' means the law. These regulations are Acts of Parliament, and following them is a legal requirement, not a choice. If you fail to comply with a statutory regulation, you are committing a criminal offense. You can think of statutory regulations as the mandatory rules of the land that keep workers and the public safe.",
        "The most important 'umbrella' law is the Health and Safety at Work Act (HASAWA), which sets the general safety duties for everyone on a job site, from the boss to the apprentice. For our trade specifically, the Electricity at Work Regulations (EAWR) is the primary statutory law we must follow to prevent death or injury from electrical systems. It is the legal rulebook for electrical safety.",
        "Other statutory regulations you will encounter include COSHH, which covers hazardous substances like solder fumes or masonry dust, and the PPE regulations, which mandate the use of safety gear like boots and goggles. You also have PUWER for work equipment, CDM for construction management, and the Environmental Act. Remember: Statutory equals Law. These documents dictate the legal safety standards that must be met to avoid criminal prosecution."
      ],
      "hint": "Focus on the fact that statutory documents are Acts of Parliament and carry the weight of the law."
    },
    {
      "title": "Non-statutory Regulations and Guidance",
      "objective": "Identify non-statutory regulations and guidance documents used in the electrical industry.",
      "retrievalTextLines": [
        "While statutory regulations are the law, 'Non-statutory' documents are technical guides that show you how to meet those laws. The most critical non-statutory document is BS 7671, also known as the IET Wiring Regulations. Even though every electrician refers to it as 'the regs,' it is actually a national technical standard, not a law passed by Parliament. It provides the detailed 'how-to' for safe installations.",
        "Think of the relationship like this: Statutory laws (like EAWR) tell you what you must achieve (safety), while non-statutory guidance (like BS 7671) tells you the technical methods to achieve it. Other non-statutory resources include the On-Site Guide, which is a practical, pocket-sized summary of BS 7671 for common tasks, and various Guidance Notes that dive deep into specific topics like testing or earthing. You might also use the Unite Union Book or specific Codes of Practice.",
        "A common mistake is thinking these are optional because they aren't 'law.' In reality, following BS 7671 is the standard way to prove you have complied with the statutory Electricity at Work Regulations in a court of law. Non-statutory equals Guidance; they are the professional blueprints for safe, high-quality electrical work."
      ],
      "hint": "Remember that BS 7671 and the On-Site Guide are technical standards, not Acts of Parliament."
    }
  ]
}

